// Sofia - Contextual Analysis Engine
const message = $json.message || '';
const from = $json.from || '';
const conversation_history = $json.history || [];
const timestamp = new Date();

// CONTEXTUAL INTELLIGENCE LAYER
function analyzeContext(msg, history) {
  const context = {
    intent: 'unknown',
    urgency: 'medium',
    customer_type: 'prospect',
    emotional_state: 'neutral',
    stage: 'initial',
    previous_interactions: history.length || 0
  };

  const msgLower = msg.toLowerCase();

  // INTENT DETECTION (Dynamic)
  if (msgLower.includes('quero') || msgLower.includes('interessado') || msgLower.includes('sim')) {
    context.intent = 'interesse_alto';
    context.urgency = 'high';
    context.emotional_state = 'positive';
  } else if (msgLower.includes('preço') || msgLower.includes('valor') || msgLower.includes('quanto')) {
    context.intent = 'consulta_preco';
    context.stage = 'consideracao';
  } else if (msgLower.includes('horário') || msgLower.includes('quando') || msgLower.includes('agenda')) {
    context.intent = 'agendamento';
    context.urgency = 'high';
  } else if (msgLower.includes('não') || msgLower.includes('nao') || msgLower.includes('depois')) {
    context.intent = 'objecao';
    context.emotional_state = 'resistance';
  } else if (msgLower.includes('?')) {
    context.intent = 'duvida';
    context.stage = 'investigacao';
  }

  // CUSTOMER TYPE DETECTION
  if (history.some(h => h.includes('ex-aluno') || h.includes('voltei'))) {
    context.customer_type = 'ex_aluno';
  } else if (history.some(h => h.includes('free pass') || h.includes('gratuito'))) {
    context.customer_type = 'free_pass';
  } else if (history.some(h => h.includes('amigo') || h.includes('indicado'))) {
    context.customer_type = 'amigo_bonus';
  }

  return context;
}

// DYNAMIC REASONING ENGINE
function decideBestAction(context) {
  const actions = [];

  // DECISION TREE BASED ON CONTEXT
  if (context.intent === 'interesse_alto') {
    if (context.customer_type === 'ex_aluno') {
      actions.push('oferecer_promocao_volta');
      actions.push('verificar_historico_valor');
    } else if (context.customer_type === 'free_pass') {
      actions.push('acelerar_conversao');
      actions.push('criar_urgencia_desconto');
    } else {
      actions.push('oferecer_free_pass');
      actions.push('agendar_avaliacao');
    }
  } else if (context.intent === 'consulta_preco') {
    actions.push('apresentar_planos_segmentado');
    actions.push('destacar_valor_vs_beneficios');
    if (context.customer_type === 'ex_aluno') {
      actions.push('aplicar_desconto_volta');
    }
  } else if (context.intent === 'objecao') {
    actions.push('quebrar_objecao_contextual');
    actions.push('oferecer_alternativa');
    actions.push('manter_relacionamento');
  } else if (context.intent === 'agendamento') {
    actions.push('verificar_agenda_disponivel');
    actions.push('confirmar_dados_contato');
  }

  return {
    primary_action: actions[0] || 'continuar_conversa',
    secondary_actions: actions.slice(1),
    reasoning: `Baseado no contexto: ${context.intent} + ${context.customer_type} + ${context.emotional_state}`
  };
}

// EXECUTE ANALYSIS
const context = analyzeContext(message, conversation_history);
const decision = decideBestAction(context);

return {
  original_message: message,
  from: from,
  timestamp: timestamp.toISOString(),
  context_analysis: context,
  sofia_decision: decision,
  conversation_stage: context.stage,
  next_workflow: `sofia_${decision.primary_action}`,
  reasoning_log: `Sofia analisou: '${message}' e decidiu: ${decision.primary_action} porque ${decision.reasoning}`
};

// Sofia Dynamic Response Generator
const context = $json.context_analysis;
const decision = $json.sofia_decision;
const customer_type = context.customer_type;
const intent = context.intent;
const from = $json.from;

// PERSONA-BASED RESPONSE TEMPLATES
const responses = {
  ex_aluno: {
    interesse_alto: `Que alegria saber que você quer voltar! 🎉\n\nTenho uma oferta especial de VOLTA que vai te surpreender:\n\n🎁 **20% de desconto** nos primeiros 3 meses\n💪 **1 semana grátis** para relembrar como é bom treinar aqui\n\nA Full Force Academia tem novidades incríveis esperando você!\n\nQuer que eu reserve essa semana grátis? É só confirmar! 🚀`,
    consulta_preco: `Oi! Para você que já fez parte da nossa família, temos condições especiais! 💪\n\n**OFERTA VOLTA POR CIMA:**\n\n🔥 Plano Mensal: R$ 143,20 (20% off)\n🔥 Plano Semestral: R$ 715,20 (20% off)\n🔥 Plano Anual: R$ 1.046,40 (20% off)\n\n**+ BÔNUS:** 1 semana grátis para decidir!\n\nEssa oferta é só para ex-alunos como você. Que tal aproveitar? 😊`
  },
  free_pass: {
    interesse_alto: `Perfeito! Vejo que você está aproveitando seu Free Pass! 🎉\n\nPara não perder o ritmo, que tal garantir sua vaga definitiva?\n\n**OFERTA EXCLUSIVA FREE PASS:**\n✅ Sem taxa de matrícula\n✅ Primeiro mês por R$ 149 (economia de R$ 30)\n✅ Acesso total aos equipamentos novos\n\nSó hoje! Confirmo sua matrícula agora? 🚀`,
    consulta_preco: `Que bom que está considerando continuar! 💪\n\n**PLANOS FULL FORCE ACADEMIA:**\n\n💥 **MAIS ESCOLHIDO:** Mensal R$ 179\n🏆 **MELHOR CUSTO:** Semestral R$ 894 (R$ 149/mês)\n👑 **VIP:** Anual R$ 1.308 (R$ 109/mês + leva amigo grátis!)\n\nComo está sendo seu Free Pass? Qual plano faz mais sentido pra você? 😊`
  },
  prospect: {
    interesse_alto: `Que ótimo! Você escolheu a academia certa! 🎉\n\n**BORA COMEÇAR?**\n\n🎁 **FREE PASS 5 DIAS** - Totalmente grátis!\n📍 Conheça nossos equipamentos novos\n💪 Experimente todas as modalidades\n👥 Sinta o clima da nossa comunidade\n\nPosso agendar sua visita para quando? Temos horários hoje mesmo! 🚀`,
    consulta_preco: `Oi! Que bom seu interesse! 😊\n\n**PLANOS FULL FORCE ACADEMIA - MATUPÁ/MT:**\n\n💚 **Mensal**: R$ 179 (flexibilidade total)\n💙 **Semestral**: R$ 894 (economia R$ 180)\n💜 **Anual**: R$ 1.308 (economia R$ 840 + bônus amigo grátis!)\n\n**DICA:** Comece com nosso **FREE PASS 5 DIAS** gratuito!\n\nQuer conhecer primeiro? Quando pode vir? 🏋️‍♀️`
  }
};

// DYNAMIC RESPONSE SELECTION
function generateResponse(customer_type, intent) {
  const template = responses[customer_type]?.[intent] || responses.prospect[intent] || responses.prospect.interesse_alto;

  // ADD PERSONALIZATION ELEMENTS
  const personalizations = {
    time_based: getTimeBasedPersonalization(),
    weather: 'Dia perfeito para treinar! ☀️',
    community: 'Em Matupá, todo mundo se conhece, e aqui não é diferente! 😊'
  };

  return template;
}

function getTimeBasedPersonalization() {
  const hour = new Date().getHours();
  if (hour < 12) return '☀️ Bom dia!';
  if (hour < 18) return '🌞 Boa tarde!';
  return '🌙 Boa noite!';
}

// GENERATE SOFIA'S RESPONSE
const response = generateResponse(customer_type, intent);

// DETERMINE NEXT ACTIONS
const next_actions = [];
if (intent === 'interesse_alto') {
  next_actions.push('follow_up_24h');
  next_actions.push('prepare_onboarding');
} else if (intent === 'consulta_preco') {
  next_actions.push('send_detailed_plans');
  next_actions.push('offer_visit');
}

return {
  to: from,
  message: response,
  sofia_reasoning: `Identifiquei ${customer_type} com ${intent}, gerando resposta personalizada`,
  next_actions: next_actions,
  follow_up_time: new Date(Date.now() + 24*60*60*1000).toISOString(),
  conversation_stage: context.stage,
  customer_score: calculateCustomerScore(context),
  academia: 'Full Force Academia',
  cidade: 'Matupá-MT'
};

function calculateCustomerScore(context) {
  let score = 50; // base
  if (context.intent === 'interesse_alto') score += 30;
  if (context.customer_type === 'ex_aluno') score += 20;
  if (context.emotional_state === 'positive') score += 15;
  if (context.urgency === 'high') score += 10;
  return Math.min(100, score);
}
